// n8n Code node (JavaScript) - Run Once for All Items
function pickText(obj) {
  if (!obj || typeof obj !== "object") return "";
  const candidates = ["output", "text", "response", "message", "content"];
  for (const k of candidates) {
    if (typeof obj[k] === "string" && obj[k].trim()) return obj[k];
  }
  for (const v of Object.values(obj)) {
    if (typeof v === "string" && v.trim()) return v;
  }
  return "";
}

let mensagemRaw = "";
try { mensagemRaw = pickText($input.first()?.json) || ""; } catch (e) {}
if (!mensagemRaw) {
  try { mensagemRaw = pickText($("AI Agent").first()?.json) || ""; } catch (e) {}
}

let mensagem = String(mensagemRaw).replace(/\r\n/g, "\n").replace(/\u00A0/g, " ").trim();

if (!mensagem) {
  mensagem = "Oi! Tive um pequeno problema técnico aqui e a minha resposta falhou. Você poderia repetir a pergunta de outra forma, por favor?";
}

const isLikelyGreeting = (txt) => /^(oi|olá|ola|boa\s*(tarde|noite|dia)|hey|e?a[ií]|tudo bem)/i.test((txt ?? "").trim());
const isLikelySignatureHead = (line) => /^(atenciosamente|com\s+carinho|abraços|abracos|obrigad[oa]|grato|grata|cordialmente|respeitosamente|att\.?)\b/i.test((line ?? "").trim());
const hasOnlyShortLines = (block) => {
  const lines = (block ?? "").split("\n").map((l) => l.trim()).filter(Boolean);
  if (lines.length === 0) return false;
  const avgLen = lines.reduce((a, b) => a + b.length, 0) / lines.length;
  return avgLen <= 28 && lines.every((l) => l.length <= 50);
};

const sentenceSplit = (paragraph) => {
  const p = (paragraph ?? "").trim();
  if (!p) return [];
  if (hasOnlyShortLines(p)) return [p];
  const parts = p.match(/[^.!?]+(?:[.!?]+["”']?)(?=\s+|$)|[^.!?]+$/g) || [p];
  const ABBR = /(?:\b(Sr|Sra|Srta|Dr|Dra|Prof|Profa|vs|p|ex|etc|aprox|pg|fig|cap)\.)$/i;
  const fixed = [];
  for (const curRaw of parts) {
    const cur = (curRaw ?? "").trim();
    if (!cur) continue;
    if (fixed.length > 0) {
      const prev = fixed[fixed.length - 1].trim();
      if (ABBR.test(prev)) {
        fixed[fixed.length - 1] = `${prev} ${cur}`.trim();
        continue;
      }
    }
    fixed.push(cur);
  }
  return fixed;
};

const groupSentences = (sentences, maxChars = 400, maxPerGroup = 3) => {
  const groups = [];
  let buf = "";
  let countInGroup = 0;
  const flush = () => {
    if (buf.trim()) groups.push(buf.trim());
    buf = "";
    countInGroup = 0;
  };
  const isUrlOrEmailOnly = (s) => /^(https?:\/\/\S+|www\.\S+|[\w.+-]+@[\w.-]+\.[a-zA-Z]{2,})$/i.test((s ?? "").trim());
  for (const sRaw of sentences) {
    const s = (sRaw ?? "").trim();
    if (!s) continue;
    const tentative = buf ? `${buf} ${s}` : s;
    const exceeds = tentative.length > maxChars;
    const tooMany = countInGroup + 1 > maxPerGroup;
    const isolate = isUrlOrEmailOnly(s);
    if ((exceeds || tooMany || isolate) && buf) flush();
    buf = buf ? `${buf} ${s}` : s;
    countInGroup++;
    if (buf.length >= maxChars * 0.9) flush();
  }
  flush();
  return groups;
};

let blocks = mensagem.split(/\n{2,}/).map((b) => b.trim()).filter(Boolean);
if (blocks.length >= 1) {
  const last = blocks[blocks.length - 1];
  const firstLine = last.split("\n")[0] ?? "";
  if (isLikelySignatureHead(firstLine) || hasOnlyShortLines(last)) {}
}
if (blocks.length >= 1) {
  const first = blocks[0];
  const firstLine = first.split("\n")[0] ?? "";
  if (isLikelyGreeting(firstLine) && first.length <= 220) {}
}

const finalBlocks = [];
for (let i = 0; i < blocks.length; i++) {
  const b = blocks[i];
  const firstLine = b.split("\n")[0] ?? "";
  const looksLikeSignature = isLikelySignatureHead(firstLine) || (i === blocks.length - 1 && hasOnlyShortLines(b));
  if (looksLikeSignature) { finalBlocks.push(b); continue; }
  if (b.length <= 500 && b.includes("\n")) { finalBlocks.push(b); continue; }
  if (b.length <= 420) { finalBlocks.push(b); continue; }
  const sentences = sentenceSplit(b);
  const grouped = groupSentences(sentences, 400, 3);
  finalBlocks.push(...grouped);
}

let remoteJid = "";
let instance = "";
try {
  remoteJid = $("Dados").first().json.remoteJid;
  instance = $("Dados").first().json.Instance;
} catch(e) {}

const outputs = finalBlocks
  .map((s) => s.replace(/[ \t]+\n/g, "\n").trim())
  .filter(Boolean)
  .map((s) => ({ json: { output: s, remoteJid: remoteJid, Instance: instance } }));

return outputs.length ? outputs : [{ json: { output: mensagem, remoteJid: remoteJid, Instance: instance } }];
